INSERT INTO job_categories (category_id, name, description) VALUES (1, '経営・企画・マネジメント職', '経営・企画・マネジメント職は、企業の戦略立案、目標設定、組織運営、資源配分などを統括し、事業全体の成長と発展を推進する役割を担います。');
INSERT INTO job_categories (category_id, name, description) VALUES (2, '事務・オフィスワーク職', '事務・オフィスワーク職は、企業や組織において、書類作成、データ入力、電話応対、来客対応、スケジュール管理、備品管理など、円滑な業務遂行をサポートする幅広いバックオフィス業務を担います。正確性と効率性が求められる職種です。');
INSERT INTO job_categories (category_id, name, description) VALUES (3, '財務・会計・経理職', '企業の資金管理、予算作成、会計処理、財務諸表作成、税務申告などを担当し、企業の財政健全性を維持・向上させる重要な役割を担います。');
INSERT INTO job_categories (category_id, name, description) VALUES (4, '人事・労務・総務職', '人事・労務・総務職は、採用、人材育成、評価などの人事業務、給与計算、社会保険、労働環境整備などの労務業務、オフィス管理、備品管理、社内イベント運営などの総務業務を横断的に担当し、従業員が働きやすい環境を構築し、企業運営を円滑に進める重要な役割を担います。');
INSERT INTO job_categories (category_id, name, description) VALUES (5, '法務・知財・内部統制職', '企業活動における法的リスクの管理、契約書や規約の作成・審査、知的財産の保護・活用、および内部統制体制の構築・運用を通じて、企業の健全な事業運営を支援する職種です。');
INSERT INTO job_categories (category_id, name, description) VALUES (6, '営業・販売・営業企画職', '顧客のニーズを理解し、自社の商品やサービスを提案・販売することで売上を創出し、市場調査や戦略立案を通じて営業活動全体を最適化する役割を担います。');
INSERT INTO job_categories (category_id, name, description) VALUES (7, 'マーケティング・広報・PR職', 'マーケティング・広報・PR職は、製品やサービスの認知度向上、ブランドイメージ構築、売上拡大を目的とし、市場調査、プロモーション戦略の立案・実行、メディアリレーション、SNS運用、広報活動など多岐にわたる業務を行います。');
INSERT INTO job_categories (category_id, name, description) VALUES (8, 'カスタマーサポート・コールセンター職', 'お客様からの製品やサービスに関する問い合わせ（電話、メール、チャットなど）に対応し、情報提供や問題解決を行います。顧客満足度向上とサービス改善に貢献する職種です。');
INSERT INTO job_categories (category_id, name, description) VALUES (9, 'コンサルタント・アナリスト職', '顧客の抱える経営課題を分析し、解決策の提案から実行支援までを一貫して行う専門家です。データ分析、戦略立案、業務改善など多岐にわたる業務を担当します。');
INSERT INTO job_categories (category_id, name, description) VALUES (10, 'ITエンジニア・ソフトウェア開発職', 'ITエンジニア・ソフトウェア開発職は、システムの設計、開発、テスト、運用保守を行う専門職です。プログラミング言語を用いてソフトウェアやアプリケーションを構築し、技術的な問題解決や新機能の実装に貢献します。');
INSERT INTO job_categories (category_id, name, description) VALUES (11, 'データサイエンティスト・AIエンジニア職', 'データサイエンティスト・AIエンジニアは、データ分析、機械学習モデル開発、AIソリューション構築を通じて、データから価値ある知見を導き出し、ビジネス課題の解決や新たな価値創造に貢献する職種です。');
INSERT INTO job_categories (category_id, name, description) VALUES (12, 'インフラ・ネットワーク・クラウドエンジニア職', 'インフラ・ネットワーク・クラウドエンジニアは、企業のIT基盤（サーバー、ネットワーク、クラウド環境など）の設計、構築、運用、保守を行います。システムの安定稼働と効率的な運用を支える重要な役割を担います。');
INSERT INTO job_categories (category_id, name, description) VALUES (13, 'セキュリティエンジニア・SOC職', 'セキュリティエンジニア・SOC職は、組織のITシステムとデータのセキュリティを確保するため、セキュリティシステムの設計・構築・運用、脆弱性診断、脅威監視、インシデント対応を行う専門職です。');
INSERT INTO job_categories (category_id, name, description) VALUES (14, 'Webデザイナー・UI/UXデザイナー職', 'Webサイトやアプリケーションの見た目（UI）と使いやすさ（UX）を設計・デザインする専門職です。ユーザーが快適にサービスを利用できるよう、視覚的魅力と機能性を両面から追求します。');
INSERT INTO job_categories (category_id, name, description) VALUES (15, 'グラフィック・映像・クリエイティブ職', 'グラフィック・映像・クリエイティブ職は、広告、Web、ゲーム、映像コンテンツなどの視覚表現を企画・制作する専門職です。デザインソフトウェアを駆使し、コンセプトに基づいたビジュアルを創出します。');
INSERT INTO job_categories (category_id, name, description) VALUES (16, 'プロダクトマネージャー・プロデューサー職', 'プロダクトマネージャー・プロデューサーは、製品やサービスの企画から開発、改善までを統括し、市場調査、ユーザーニーズ分析、戦略策定、開発ロードマップの管理、チーム連携を通じて、製品の成功とビジネス目標達成に貢献する役割です。');
INSERT INTO job_categories (category_id, name, description) VALUES (17, 'ゲームクリエイター・3D・CG職', 'ゲームのキャラクター、背景、アイテムなどの3DモデルやCG映像を制作し、ゲームの世界観を視覚的に表現する専門職です。モデリング、テクスチャリング、アニメーション、エフェクト制作などを担当します。');
INSERT INTO job_categories (category_id, name, description) VALUES (18, '機械・電気・電子エンジニア職', '機械・電気・電子エンジニアは、機械、電気、電子部品やシステムの設計、開発、製造、評価、保守を行います。製品や設備の機能・性能向上、技術課題の解決が主な役割です。');
INSERT INTO job_categories (category_id, name, description) VALUES (19, '化学・素材・食品エンジニア職', '化学・素材・食品エンジニアは、化学製品、新素材、医薬品、食品などの研究開発、製造プロセスの設計・改善、品質管理、生産設備管理などを行います。新しい技術や製品を生み出し、社会に貢献する役割を担います。');
INSERT INTO job_categories (category_id, name, description) VALUES (20, '建築・土木・施工管理職', '建築・土木・施工管理職は、建築物や土木構造物の建設プロジェクトにおいて、工程、品質、コスト、安全を管理し、計画通りに工事が進むよう指揮・監督する役割を担います。関係者との調整も重要な業務です。');
INSERT INTO job_categories (category_id, name, description) VALUES (21, '製造・生産技術・品質管理職', '製造・生産技術・品質管理職は、製品の企画から生産、出荷までの一連のプロセスにおいて、製造ラインの設計・改善、生産効率の向上、品質基準の設定と管理、不良品の解析と対策、コスト削減などを担当します。');
INSERT INTO job_categories (category_id, name, description) VALUES (22, '研究開発・技術開発職', '新製品や新技術の開発、または既存製品・技術の改良を担います。基礎研究、応用研究、試作品開発、評価、量産化への技術移転など、幅広い工程に携わります。');
INSERT INTO job_categories (category_id, name, description) VALUES (23, '医師・看護師・薬剤師など医療専門職', '医師は診断・治療、看護師は患者ケア、薬剤師は薬の調剤・管理を担い、チームで患者の健康をサポートする専門職です。');
INSERT INTO job_categories (category_id, name, description) VALUES (24, '介護・福祉・保育職', '高齢者や障がい者の生活支援、児童の健全な育成を支える専門職です。身体介護、生活援助、相談業務、学習支援などを通じて、対象者のQOL向上と社会参加を促進します。');
INSERT INTO job_categories (category_id, name, description) VALUES (25, '教員・講師・教育支援職', '教員・講師・教育支援職は、小・中・高・大学や専門学校などで、学生や生徒に教科内容を教え、学習指導、生活指導、進路指導を行う専門職です。授業の計画・実施、教材作成、評価、生徒や保護者との連携なども含まれます。');
INSERT INTO job_categories (category_id, name, description) VALUES (26, 'クリエイティブライター・編集・翻訳職', 'クライアントの要望に応じ、魅力的な文章を作成するライティング、既存コンテンツを校正・修正する編集、そして多言語間で情報を正確に伝える翻訳業務を行う職種です。広告、Webコンテンツ、書籍など多岐にわたる媒体で活躍します。');
INSERT INTO job_categories (category_id, name, description) VALUES (27, 'アーティスト・デザイナー・音楽・映像関連職', 'アーティスト・デザイナー・音楽・映像関連職は、絵画、グラフィック、Web、ファッション、プロダクト、音楽、映像、アニメーションなど多岐にわたる分野で、独自の創造性や技術を活かして作品やサービスを生み出し、視覚的・聴覚的な表現を通じてメッセージを伝え、人々に感動や情報を提供する専門職です。');
INSERT INTO job_categories (category_id, name, description) VALUES (28, '公務員・行政職', '地方公共団体や国の機関で、住民サービス、政策立案、事業運営などを担当し、社会全体の公共の利益のために働く職種です。');
INSERT INTO job_categories (category_id, name, description) VALUES (29, '警察・消防・自衛官職', '警察官は治安維持、犯罪捜査、交通取り締まりを行います。消防官は火災の消火活動、救助活動、防災指導を担当します。自衛官は国の防衛、災害派遣、国際平和協力活動に従事します。');
INSERT INTO job_categories (category_id, name, description) VALUES (30, '弁護士・会計士・税理士など専門士業', '法律、会計、税務などの専門知識と資格を持つプロフェッショナル。個人や企業の課題解決のため、法的助言、財務監査、税務申告代理、コンサルティングなど多岐にわたる専門サービスを提供します。');
INSERT INTO job_categories (category_id, name, description) VALUES (31, '金融・保険・証券・不動産関連職', '金融・保険・証券・不動産関連職は、銀行、保険会社、証券会社、不動産会社などに所属し、資金の貸付・運用、保険商品の提供、有価証券の取引、不動産の売買・管理などを通じて、個人や法人の資産形成や経済活動を支援する専門職です。');
INSERT INTO job_categories (category_id, name, description) VALUES (32, 'サービス・販売・接客職', 'お客様と直接関わり、商品やサービスの提供、案内、販売、お問い合わせ対応などを行います。顧客満足度向上を目指し、ホスピタリティ精神を持って対応する職種です。');
INSERT INTO job_categories (category_id, name, description) VALUES (33, '飲食・調理・ホスピタリティ職', '飲食・調理・ホスピタリティ職は、レストラン、ホテル、カフェなどで、お客様に料理やサービスを提供し、快適な時間や空間を創造する仕事です。調理、接客、施設管理など多岐にわたります。');
INSERT INTO job_categories (category_id, name, description) VALUES (34, '運輸・物流・ドライバー職', '人や荷物を目的地まで安全かつ効率的に運搬する仕事です。輸送計画の立案、車両の運転・点検、積卸し作業、配送ルートの最適化などが主な業務内容となります。');
INSERT INTO job_categories (category_id, name, description) VALUES (35, '清掃・メンテナンス・警備職', '建物や施設の清潔さ、機能性、安全性を維持するための業務です。清掃は衛生管理を、メンテナンスは設備維持・点検を、警備は人や財産の安全確保を担当します。');
INSERT INTO job_categories (category_id, name, description) VALUES (36, '農林水産関連職', '農林水産関連職は、農業、林業、漁業といった第一次産業に従事し、食料生産、森林管理、水産資源の確保と育成などを行います。作物の栽培、家畜の飼育、木材の伐採・育成、魚介類の養殖・漁獲などが主な業務です。');
INSERT INTO job_categories (category_id, name, description) VALUES (37, '宗教・文化・芸能・スポーツ職', '宗教・文化・芸能・スポーツ職は、信仰の伝達、文化芸術の創造・継承、人々に感動を与えるエンターテイメント活動、そしてスポーツを通じた身体能力の追求や健康増進など、多岐にわたる分野で人々の精神的・肉体的な豊かさに貢献する専門職の総称です。それぞれの分野で専門的な知識や技能を活かし、社会に価値を提供します。');
INSERT INTO job_categories (category_id, name, description) VALUES (38, '研究者・学術職', '特定の分野において、新たな知識の発見、理論の構築、既存の知識の検証などを行う専門職です。実験、調査、データ分析、論文執筆などを通じて、専門分野の発展に貢献します。');
INSERT INTO job_categories (category_id, name, description) VALUES (39, '起業家・フリーランス・クリエイター職', '起業家・フリーランス・クリエイター職は、特定の企業に属さず、自身のスキルやアイデアを活かして事業を立ち上げたり、独立してサービスや作品を提供する職種です。自己責任で企画、制作、営業、マーケティングなど多岐にわたる業務を担い、自身の裁量で働くスタイルが特徴です。自由度が高い反面、すべての業務を自分で管理し、収益を上げていく必要があります。');
